export function joinPosix(...parts) {
  const segs = parts.join('/').split('/').filter((s) => s !== '' && s !== '.');
  const out = [];
  for (const seg of segs) {
    if (seg === '..' && out.length > 0 && out[out.length - 1] !== '..') {
      out.pop();
    } else {
      out.push(seg);
    }
  }
  return out.join('/');
}
